insert into public.project_events (slug, group_key, status, name, type, description, event_date_label, event_time_label, location, image_url, details, registration_status, registration_label, registration_link, sort_order)
values
  ('quiz', 'megabattle', 'published', 'Квиз', 'интеллектуальная битва', 'Командная игра для факультетов: быстрые вопросы, музыкальные и визуальные раунды, мемы, логика и немного хаоса. Хорошая точка входа для тех, кто хочет почувствовать сезон без сцены и репетиций.', 'дата уточняется', 'вечер', 'Университет ИТМО', '/images/events/event1.jpg', '["команды от факультетов","баллы в общий зачёт","формат для новичков"]'::jsonb, 'soon', 'Регистрация скоро', '', 0),
  ('quest', 'megabattle', 'published', 'Квест', 'маршрут · задания · город', 'Большой маршрут с заданиями, шифрами и точками взаимодействия. Команды двигаются по локациям, собирают подсказки, выполняют челленджи и забирают очки за скорость, смекалку и командность.', 'дата уточняется', 'день', 'кампус и городские точки', '/images/events/event2.jpg', '["несколько локаций","факультетские команды","фото- и видео-задания"]'::jsonb, 'soon', 'Регистрация скоро', '', 10),
  ('gala', 'megabattle', 'published', 'Гала-концерт', 'главная сцена сезона', 'Финальная большая сцена Megabattle: номера факультетов, награды, лучшие участники, общий рейтинг и тот самый момент, когда весь сезон превращается в одну большую историю.', 'дата уточняется', 'вечер', 'площадка будет объявлена позже', '/images/events/event1.jpg', '["главное событие","номера факультетов","награждение"]'::jsonb, 'closed', 'Регистрация пока закрыта', '', 20),
  ('game', 'megabattle', 'published', 'Game', 'игровой формат', 'Соревновательный игровой вечер: настолки, консоли, быстрые турниры и командные механики. Формат для тех, кто хочет принести факультету очки без микрофона, но с азартом.', 'дата уточняется', 'вечер', 'Университет ИТМО', '/images/events/event2.jpg', '["турнирные сетки","командные очки","несколько игровых зон"]'::jsonb, 'soon', 'Регистрация скоро', '', 30),
  ('special-event', 'megabattle', 'published', 'Special Event', 'секретный формат', 'Отдельный специвент сезона, который лучше не спойлерить заранее. Здесь можно будет быстро заменить описание на финальный анонс из админки или базы.', 'дата уточняется', 'следите за анонсами', 'будет объявлено в каналах проекта', '/images/about-image.png', '["секретный формат","ограниченное число мест","анонс в соцсетях"]'::jsonb, 'closed', 'Анонс скоро', '', 40),
  ('chto', 'partners', 'published', 'Творческое объединение «Что»', 'театр · перформанс · творческая лаборатория', 'Партнёрское творческое объединение для тех, кто хочет пробовать театр, перформанс, актёрские практики и сценические эксперименты вне основной сетки Megabattle.', 'по расписанию объединения', 'анонсы в Telegram', 'площадки ИТМО и партнёров', '/images/events/event1.jpg', '["театр","сценическая практика","@chtotheatre"]'::jsonb, 'open', 'Перейти в Telegram', 'https://t.me/chtotheatre', 50),
  ('fashion-show', 'partners', 'published', 'Fashion Show', 'мода · стиль · показ', 'Партнёрский fashion-формат про стиль, показы, визуальные образы и командную работу вокруг моды. Отличная точка для тех, кто хочет в костюм, продакшен, подиум или backstage.', 'по расписанию команды', 'анонсы в Telegram', 'площадки ИТМО', '/images/events/event2.jpg', '["показы","стиль","@itmo_fashion"]'::jsonb, 'open', 'Перейти в Telegram', 'https://t.me/itmo_fashion', 60),
  ('lab-sport', 'partners', 'published', 'ЛАБ', 'футбол · баскетбол · волейбол', 'Спортивное направление для тех, кто хочет играть за свою команду и собирать вокруг факультета отдельный соревновательный вайб: футбол, баскетбол, волейбол и командные активности.', 'по спортивному календарю', 'тренировки и игры', 'спортивные площадки ИТМО', '/images/about-image.png', '["футбол","баскетбол","волейбол"]'::jsonb, 'closed', 'Контакты появятся позже', '', 70),
  ('punchline', 'partners', 'published', 'Панчлайн', 'стендап · юмор · открытый микрофон', 'Партнёрский юмористический формат: стендап, открытые микрофоны, авторские тексты и сцена для тех, кто хочет проверять шутки на живой аудитории.', 'по расписанию клуба', 'анонсы в Telegram', 'площадки ИТМО', '/images/events/event1.jpg', '["стендап","открытый микрофон","@itmopunchline"]'::jsonb, 'open', 'Перейти в Telegram', 'https://t.me/itmopunchline', 80)
on conflict (slug) do update set
